const appliedIds = items
  .map(i => String(i.json['Job ID'] || ''))
  .filter(Boolean);
return [{ json: { appliedIds } }];

const appliedIds = new Set(
  $('Build Applied IDs Set').first().json.appliedIds.map(String)
);
const jobId = String($input.item.json.id || '');
return [{ json: { ...$input.item.json, alreadyApplied: appliedIds.has(jobId) } }];

const j = $input.item.json;
const title      = String(j.title || '').toLowerCase();
const seniority  = String(j.seniorityLevel || '').toLowerCase();
const functions  = Array.isArray(j.jobFunctions)
  ? j.jobFunctions.join(' ').toLowerCase()
  : String(j.jobFunctions || '').toLowerCase();
const desc = String(j.descriptionHtml || '').replace(/<[^>]*>/g,' ').toLowerCase();

const goodTitle   = /(intern|internship|co-op|coop|student|junior|entry|software|developer|engineer|qa|automation|data|ai|ml|backend|it\b)/.test(title);
const badTitle    = /(\bsales\b|marketing|account executive|nurse|customer service|recruiter|insurance|financial advisor|cashier)/.test(title);
const seniorBad   = /(senior|staff|principal|manager|director|lead)/.test(seniority) || /(\bmanager\b|director|\blead\b)/.test(title);
const techSignals = (title + ' ' + functions + ' ' + desc)
  .match(/python|java(?:script)?|sql|api|cloud|aws|azure|gcp|automation|backend|react|node\.?js|\bai\b|machine learning|data|\bqa\b|testing|it support|typescript|c\+\+|kotlin|swift/g) || [];

const cheapPass = goodTitle && !badTitle && !seniorBad && techSignals.length >= 1;
return [{ json: { ...j, cheapPass, techSignalCount: techSignals.length } }];

