const passed = items.filter(i => !i.json.alreadyApplied);

if (passed.length === 0) {
  return [{ json: { _skipAll: true, alreadyApplied: true } }];
}

return passed;

for (const item of items) {
  const j = item.json;

  const title = String(j.title || '').toLowerCase();
  const seniority = String(j.seniorityLevel || '').toLowerCase();
  const functions = Array.isArray(j.jobFunctions)
    ? j.jobFunctions.join(' ').toLowerCase()
    : String(j.jobFunctions || '').toLowerCase();
  const desc = String(j.descriptionHtml || '')
    .replace(/<[^>]*>/g, ' ')
    .toLowerCase();

  let score = 0;
  const reasons = [];

  if (/(intern|internship|co-op|coop|student)/.test(title)) {
    score += 4;
    reasons.push('student/intern title');
  }

  if (/(software|developer|engineer|qa|automation|data|ai|ml|backend|it)/.test(title)) {
    score += 3;
    reasons.push('technical title');
  }

  if (/(engineering|information technology|it|data|qa|software)/.test(functions)) {
    score += 2;
    reasons.push('technical function');
  }

  const skillMatches = desc.match(
    /python|java|javascript|typescript|sql|api|cloud|aws|azure|gcp|react|node|automation|testing|machine learning|ai|data/g
  ) || [];

  score += Math.min(skillMatches.length, 4);
  if (skillMatches.length) {
    reasons.push(`skills:${skillMatches.length}`);
  }

  if (/(sales|marketing|recruiter|cashier|nurse|customer service|account executive)/.test(title)) {
    score -= 6;
    reasons.push('non-technical title');
  }

  if (
    /(senior|staff|principal|manager|director|lead)/.test(seniority) ||
    /(manager|director|lead|principal|staff|senior)/.test(title)
  ) {
    score -= 5;
    reasons.push('too senior');
  }

  let route = 'llm_review';
  if (score >= 7) route = 'auto_pass';
  else if (score <= 1) route = 'auto_reject';

  item.json.localScore = score;
  item.json.scoreReasons = reasons;
  item.json.route = route;
}

return items;
